"use client"

import { useState } from "react"
import {
    DndContext,
    DragOverlay,
    closestCorners,
    KeyboardSensor,
    PointerSensor,
    useSensor,
    useSensors,
    DragStartEvent,
    DragOverEvent,
    DragEndEvent,
} from "@dnd-kit/core"
import {
    arrayMove,
    SortableContext,
    sortableKeyboardCoordinates,
    verticalListSortingStrategy,
} from "@dnd-kit/sortable"
import { Lead } from "@inmocms/shared"
import { updateLeadStatus } from "@/app/actions/leads"
import { toast } from "sonner"
import { KanbanColumn } from "./kanban-column"
import { KanbanCard } from "./kanban-card"

// Definir las columnas fijas del pipeline
const COLUMNS = [
    { id: "new", title: "Nuevos", color: "bg-blue-50 text-blue-700" },
    { id: "contacted", title: "Contactados", color: "bg-indigo-50 text-indigo-700" },
    { id: "visit_scheduled", title: "Visitas", color: "bg-purple-50 text-purple-700" },
    { id: "offer", title: "Ofertas", color: "bg-orange-50 text-orange-700" },
    { id: "closing", title: "Cierre", color: "bg-green-50 text-green-700" },
    { id: "lost", title: "Perdidos", color: "bg-red-50 text-red-700" },
]

interface Props {
    initialLeads: Lead[]
}

export function KanbanBoard({ initialLeads }: Props) {
    // Agrupar leads por estado
    const [leads, setLeads] = useState<Lead[]>(initialLeads)
    const [activeId, setActiveId] = useState<string | null>(null)

    const sensors = useSensors(
        useSensor(PointerSensor),
        useSensor(KeyboardSensor, {
            coordinateGetter: sortableKeyboardCoordinates,
        })
    )

    const handleDragStart = (event: DragStartEvent) => {
        setActiveId(event.active.id as string)
    }

    const handleDragOver = (event: DragOverEvent) => {
        const { active, over } = event
        if (!over) return

        const activeId = active.id
        const overId = over.id

        // Find the containers
        const activeContainer = leads.find(l => l.id === activeId)?.status
        // overId could be a column id or a card id
        let overContainer = COLUMNS.find(c => c.id === overId)?.id || leads.find(l => l.id === overId)?.status

        if (!activeContainer || !overContainer || activeContainer === overContainer) {
            return
        }

        // Optimistic UI update during drag
        setLeads((prev) => {
            const activeItems = prev.filter(l => l.status === activeContainer)
            const overItems = prev.filter(l => l.status === overContainer)

            const activeIndex = activeItems.findIndex((l) => l.id === activeId)
            const overIndex = overItems.findIndex((l) => l.id === overId)

            let newIndex
            if (COLUMNS.some(c => c.id === overId)) {
                newIndex = overItems.length + 1
            } else {
                const isBelowOverItem =
                    over &&
                    active.rect.current.translated &&
                    active.rect.current.translated.top >
                    over.rect.top + over.rect.height
                const modifier = isBelowOverItem ? 1 : 0
                newIndex = overIndex >= 0 ? overIndex + modifier : overItems.length + 1
            }

            return prev.map(l => {
                if (l.id === activeId) {
                    return { ...l, status: overContainer as string }
                }
                return l
            })
        })
    }

    const handleDragEnd = async (event: DragEndEvent) => {
        const { active, over } = event
        setActiveId(null)

        if (!over) return

        const activeId = active.id as string
        const overId = over.id as string

        const activeLead = leads.find(l => l.id === activeId)
        if (!activeLead) return

        // Determinar el nuevo estado
        let newStatus = COLUMNS.find(c => c.id === overId)?.id

        // Si se soltó sobre otra tarjeta, obtener el estado de esa tarjeta
        if (!newStatus) {
            const overLead = leads.find(l => l.id === overId)
            if (overLead) {
                newStatus = overLead.status
            }
        }

        if (newStatus && activeLead.status !== newStatus) {
            // Actualizar estado en el backend
            try {
                await updateLeadStatus(activeId, newStatus)
                toast.success("Estado actualizado")
            } catch (error) {
                console.error("Failed to update status", error)
                toast.error("Error al actualizar estado")
                // Revertir cambio optimista si falla (opcional, por simplicidad no implementado aquí completo)
            }
        }
    }

    return (
        <DndContext
            sensors={sensors}
            collisionDetection={closestCorners}
            onDragStart={handleDragStart}
            onDragOver={handleDragOver}
            onDragEnd={handleDragEnd}
        >
            <div className="flex h-full gap-4 overflow-x-auto pb-4">
                {COLUMNS.map((col) => (
                    <KanbanColumn
                        key={col.id}
                        id={col.id}
                        title={col.title}
                        color={col.color}
                        leads={leads.filter((l) => l.status === col.id)}
                    />
                ))}
            </div>
            <DragOverlay>
                {activeId ? (
                    <KanbanCard lead={leads.find((l) => l.id === activeId)!} />
                ) : null}
            </DragOverlay>
        </DndContext>
    )
}

"use client"

import { useSortable } from "@dnd-kit/sortable"
import { CSS } from "@dnd-kit/utilities"
import { Lead } from "@inmocms/shared"
import { Card, CardContent } from "@/components/ui/card"
import { Avatar, AvatarFallback } from "@/components/ui/avatar"
import { Badge } from "@/components/ui/badge"
import { Calendar, Phone, Mail } from "lucide-react"

interface Props {
    lead: Lead
}

export function KanbanCard({ lead }: Props) {
    const {
        attributes,
        listeners,
        setNodeRef,
        transform,
        transition,
        isDragging,
    } = useSortable({
        id: lead.id,
        data: {
            type: "Lead",
            lead,
        },
    })

    const style = {
        transform: CSS.Transform.toString(transform),
        transition,
    }

    if (isDragging) {
        return (
            <div
                ref={setNodeRef}
                style={style}
                className="opacity-50 h-[140px] rounded-xl border-2 border-dashed border-blue-500 bg-blue-50"
            />
        )
    }

    return (
        <div ref={setNodeRef} style={style} {...attributes} {...listeners}>
            <Card className="border-none shadow-sm hover:shadow-md transition-all cursor-grab active:cursor-grabbing bg-white group">
                <CardContent className="p-4 space-y-3">
                    <div className="flex items-start justify-between gap-2">
                        <div className="flex items-center gap-2">
                            <Avatar className="h-8 w-8 border border-gray-100">
                                <AvatarFallback className="bg-blue-50 text-blue-600 text-[10px] font-bold">
                                    {lead.name.substring(0, 2).toUpperCase()}
                                </AvatarFallback>
                            </Avatar>
                            <div>
                                <h4 className="text-sm font-bold text-gray-800 line-clamp-1">{lead.name}</h4>
                                <span className="text-[10px] text-gray-400 font-medium block">
                                    {new Date(lead.created_at).toLocaleDateString()}
                                </span>
                            </div>
                        </div>
                        <Badge variant="outline" className={`text-[9px] font-bold uppercase border-none px-2 py-0.5 ${lead.interest_type === 'buy' ? 'bg-green-50 text-green-600' : 'bg-purple-50 text-purple-600'
                            }`}>
                            {lead.interest_type === 'buy' ? 'Compra' : 'Alquiler'}
                        </Badge>
                    </div>

                    <div className="space-y-1">
                        {lead.email && (
                            <div className="flex items-center gap-2 text-[11px] text-gray-500">
                                <Mail className="h-3 w-3" />
                                <span className="truncate">{lead.email}</span>
                            </div>
                        )}
                        {lead.phone && (
                            <div className="flex items-center gap-2 text-[11px] text-gray-500">
                                <Phone className="h-3 w-3" />
                                <span>{lead.phone}</span>
                            </div>
                        )}
                    </div>

                    <div className="pt-2 border-t border-gray-50 flex items-center justify-between">
                        <div className="flex items-center gap-1">
                            <div className="h-1.5 w-16 bg-gray-100 rounded-full overflow-hidden">
                                <div
                                    className={`h-full rounded-full ${lead.scoring > 70 ? 'bg-green-500' : 'bg-orange-400'}`}
                                    style={{ width: `${lead.scoring}%` }}
                                />
                            </div>
                        </div>
                        <span className="text-[10px] font-bold text-gray-400">
                            {lead.source || 'Directo'}
                        </span>
                    </div>
                </CardContent>
            </Card>
        </div>
    )
}

import { getPropertyById, updateProperty } from "@/app/actions/properties"
import { notFound, redirect } from "next/navigation"
import PropertyEditForm from "./form"

export default async function EditPropertyPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = await params
    const property = await getPropertyById(id)

    if (!property) {
        notFound()
    }

    return <PropertyEditForm property={property} />
}
